import{_ as l,c as r,o,ag as a}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"Skills / Agent Skills：可复用技能与编排","description":"","frontmatter":{"order":9},"headers":[],"relativePath":"ai/agent-skills.md","filePath":"ai/agent-skills.md","lastUpdated":1772197851000}'),i={name:"ai/agent-skills.md"};function s(n,t,e,g,d,h){return o(),r("div",null,t[0]||(t[0]=[a('<h1 id="skills-agent-skills-可复用技能与编排" tabindex="-1">Skills / Agent Skills：可复用技能与编排 <a class="header-anchor" href="#skills-agent-skills-可复用技能与编排" aria-label="Permalink to &quot;Skills / Agent Skills：可复用技能与编排&quot;">​</a></h1><blockquote><p>📅 主题：Agent Skills — 技能定义、编排与扩展</p></blockquote><h2 id="一、什么是-agent-skills" tabindex="-1">一、什么是 Agent Skills <a class="header-anchor" href="#一、什么是-agent-skills" aria-label="Permalink to &quot;一、什么是 Agent Skills&quot;">​</a></h2><p><strong>Agent Skills（或简称 Skills）</strong> 指的是：把 AI Agent 的<strong>某一类能力</strong>封装成可复用、可组合的「技能单元」，让 Agent 在需要时按描述或触发条件调用，而不是每次都在对话里临时写一大段说明。</p><p>可以类比：</p><ul><li><strong>函数</strong>：把一段逻辑封装成「输入 → 输出」，多处调用。</li><li><strong>技能</strong>：把「在什么情况下、按什么步骤、用什么规范做事」封装成一份说明（常以 Markdown 或结构化配置存在），Agent 在匹配到场景时加载并遵循。</li></ul><p>因此，Skills 解决的是：</p><ul><li><strong>可复用</strong>：一次写好，多轮对话、多个任务都能用。</li><li><strong>可发现</strong>：通过名称、描述、触发条件让系统或用户知道「有哪些技能、何时该用」。</li><li><strong>可编排</strong>：多个技能可以组合成更复杂的工作流（先查库再生成、先审查再提交等）。</li></ul><p>在不同产品里，Skills 的形态略有差异（例如 Cursor 的 <code>.cursor/skills/</code> 下的 <code>SKILL.md</code>，或其他平台的「技能卡片」「Action」等），但核心思想一致：<strong>把能力模块化、描述清楚、便于发现与组合</strong>。</p><hr><h2 id="二、skills-与-prompt、工具、rag-的关系" tabindex="-1">二、Skills 与 Prompt、工具、RAG 的关系 <a class="header-anchor" href="#二、skills-与-prompt、工具、rag-的关系" aria-label="Permalink to &quot;二、Skills 与 Prompt、工具、RAG 的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>作用</th><th>与 Skills 的关系</th></tr></thead><tbody><tr><td><strong>Prompt</strong></td><td>单次请求里「说什么、怎么说」</td><td>技能里往往包含<strong>固定说明与模板</strong>，相当于可复用的 Prompt 片段；调用技能时会把技能内容注入上下文</td></tr><tr><td><strong>工具 (Tools)</strong></td><td>调用外部 API、执行代码、查库等</td><td>技能可以<strong>规定何时、如何调用哪些工具</strong>；一份技能 = 使用某类工具的「说明书」</td></tr><tr><td><strong>RAG</strong></td><td>从知识库检索再生成</td><td>技能可以约定「先检索哪类文档、再按什么格式回答」，即<strong>检索+生成的流程</strong>被封装成技能</td></tr><tr><td><strong>MCP</strong></td><td>工具与资源的标准化协议</td><td>MCP 提供「有哪些工具/资源」；Skills 提供「在什么场景下、按什么步骤使用它们」</td></tr></tbody></table><p>因此：<strong>Skills 是「用法的封装」</strong>，Prompt 管单次表述，工具/MCP 管能力接口，RAG 管检索与生成流程，Skills 管「什么时候、按什么规范去用它们」。</p><hr><h2 id="三、技能如何被描述与发现" tabindex="-1">三、技能如何被描述与发现 <a class="header-anchor" href="#三、技能如何被描述与发现" aria-label="Permalink to &quot;三、技能如何被描述与发现&quot;">​</a></h2><h3 id="_3-1-技能描述-description" tabindex="-1">3.1 技能描述（Description） <a class="header-anchor" href="#_3-1-技能描述-description" aria-label="Permalink to &quot;3.1 技能描述（Description）&quot;">​</a></h3><p>一份技能通常需要<strong>简短、明确的描述</strong>，用于：</p><ul><li><strong>发现</strong>：系统或用户根据关键词、场景判断「是否该用这个技能」。</li><li><strong>注入</strong>：被选中的技能内容会加入 Agent 的上下文（系统提示或当前轮），指导本次行为。</li></ul><p>描述最好同时说明：</p><ul><li><strong>做什么（WHAT）</strong>：例如「按团队规范做代码审查」「根据 git diff 生成提交信息」。</li><li><strong>何时用（WHEN）</strong>：例如「在用户请求代码审查、提到 PR、或要求写 commit message 时使用」。</li></ul><p>这样 Agent 或路由逻辑才能在高相关性场景下自动选用该技能。</p><h3 id="_3-2-技能内容结构" tabindex="-1">3.2 技能内容结构 <a class="header-anchor" href="#_3-2-技能内容结构" aria-label="Permalink to &quot;3.2 技能内容结构&quot;">​</a></h3><p>技能内容通常包含：</p><ul><li><strong>元信息</strong>：名称、描述、可选标签或分类。</li><li><strong>使用说明</strong>：步骤、检查项、注意事项。</li><li><strong>模板与格式</strong>：输出结构、示例（如 commit 格式、报告模板）。</li><li><strong>可选</strong>：引用外部文档（如详细规范、示例库）、可执行脚本的调用方式。</li></ul><p>保持「核心说明精简、细节外挂」有利于控制上下文长度，需要时再读取详细文档或执行脚本。</p><h3 id="_3-3-触发方式" tabindex="-1">3.3 触发方式 <a class="header-anchor" href="#_3-3-触发方式" aria-label="Permalink to &quot;3.3 触发方式&quot;">​</a></h3><ul><li><strong>显式</strong>：用户说「用代码审查技能」「按 RAG 流程回答」。</li><li><strong>隐式</strong>：系统根据用户意图、当前任务类型自动匹配技能描述中的 WHEN，选择加载哪些技能。</li></ul><p>技能描述里的 WHEN 写得好，隐式触发才可靠。</p><hr><h2 id="四、技能设计原则-通用" tabindex="-1">四、技能设计原则（通用） <a class="header-anchor" href="#四、技能设计原则-通用" aria-label="Permalink to &quot;四、技能设计原则（通用）&quot;">​</a></h2><h3 id="_4-1-高内聚、可复用" tabindex="-1">4.1 高内聚、可复用 <a class="header-anchor" href="#_4-1-高内聚、可复用" aria-label="Permalink to &quot;4.1 高内聚、可复用&quot;">​</a></h3><p>一个技能只负责一类任务或一种流程，避免「大杂烩」。这样：</p><ul><li>更容易被正确触发（描述清晰）。</li><li>可以在不同场景下复用、组合。</li></ul><h3 id="_4-2-描述具体、含触发词" tabindex="-1">4.2 描述具体、含触发词 <a class="header-anchor" href="#_4-2-描述具体、含触发词" aria-label="Permalink to &quot;4.2 描述具体、含触发词&quot;">​</a></h3><ul><li>描述里写出<strong>具体能力</strong>和<strong>典型触发词/场景</strong>（如「PR」「commit message」「PDF 提取」），便于匹配。</li><li>避免空泛的「帮助用户」「处理文档」等表述。</li></ul><h3 id="_4-3-适度自由与约束" tabindex="-1">4.3 适度自由与约束 <a class="header-anchor" href="#_4-3-适度自由与约束" aria-label="Permalink to &quot;4.3 适度自由与约束&quot;">​</a></h3><ul><li><strong>高自由度</strong>：多解并存、依赖上下文的（如代码风格建议），用自然语言说明原则即可。</li><li><strong>高约束</strong>：流程固定、格式严格、易出错的（如发布流程、数据库脚本），用步骤、检查项、模板甚至固定脚本约束。</li></ul><p>根据任务「易错程度」决定写多细。</p><h3 id="_4-4-渐进式展开" tabindex="-1">4.4 渐进式展开 <a class="header-anchor" href="#_4-4-渐进式展开" aria-label="Permalink to &quot;4.4 渐进式展开&quot;">​</a></h3><ul><li>主文件里放「何时用 + 核心步骤 + 模板/示例」。</li><li>详细规范、长示例放到单独文档，技能里只给链接或文件名，需要时再读，避免一次性塞满上下文。</li></ul><hr><h2 id="五、技能编排与组合" tabindex="-1">五、技能编排与组合 <a class="header-anchor" href="#五、技能编排与组合" aria-label="Permalink to &quot;五、技能编排与组合&quot;">​</a></h2><p><strong>编排</strong>指：把多个技能或步骤组合成一条完整流程。</p><ul><li><strong>顺序</strong>：先执行技能 A（如检索文档），再执行技能 B（如按模板生成报告）。</li><li><strong>条件</strong>：若用户要求「带引用」，则启用「引用标注」技能；否则只生成摘要。</li><li><strong>并行</strong>：某些场景下可并行调用多个技能（如同时查多个知识库），再合并结果。</li></ul><p>实现方式可以是：</p><ul><li>在编排层（工作流引擎、Agent 调度）配置「步骤 → 技能/工具」的映射；</li><li>或在某一份「总控技能」里用自然语言写出「先做什么、再做什么、遇到什么情况用哪个技能」，由 Agent 按说明执行。</li></ul><p>技能设计得越模块化，编排时就越灵活。</p><hr><h2 id="六、与-mcp、rag-的配合" tabindex="-1">六、与 MCP、RAG 的配合 <a class="header-anchor" href="#六、与-mcp、rag-的配合" aria-label="Permalink to &quot;六、与 MCP、RAG 的配合&quot;">​</a></h2><ul><li><strong>MCP</strong> 定义了「有哪些工具、资源可用」（例如数据库、文件、API）。Skills 定义「在什么任务下、按什么规范使用这些工具」——例如「查询数据库时先看 schema、再拼 SQL、再校验结果」可以写成一个技能，内部引用 MCP 暴露的数据库工具。</li><li><strong>RAG</strong> 提供「检索 → 注入 → 生成」的能力。可以有一个「RAG 问答」技能：规定检索哪些集合、Top-K 与重排序策略、Prompt 模板和引用格式，这样每次做 RAG 时都一致、可复现。</li></ul><p>Skills 不替代 MCP 或 RAG，而是<strong>在它们之上加一层用法与策略</strong>，便于统一维护和复用。</p><hr><h2 id="七、小结" tabindex="-1">七、小结 <a class="header-anchor" href="#七、小结" aria-label="Permalink to &quot;七、小结&quot;">​</a></h2><ol><li><strong>Agent Skills</strong> = 把一类能力封装成可复用、可发现的「技能单元」，通过描述（WHAT + WHEN）被选中并注入上下文，指导 Agent 行为。</li><li><strong>与 Prompt / 工具 / RAG / MCP</strong>：Skills 是「用法的封装」；Prompt 管表述，工具/MCP 管接口，RAG 管检索与生成，Skills 管何时、按何规范使用它们。</li><li><strong>描述与发现</strong>：描述要具体、含触发词；内容结构清晰，核心精简、细节可外挂；支持显式/隐式触发。</li><li><strong>设计原则</strong>：高内聚、可复用；描述具体；按任务易错程度决定约束程度；渐进式展开。</li><li><strong>编排</strong>：通过顺序、条件、并行组合多个技能，形成完整工作流；与 MCP、RAG 配合可形成「工具 + 用法 + 检索策略」的统一层。</li></ol>',54)]))}const c=l(i,[["render",s]]);export{u as __pageData,c as default};
